import express from 'express';
import { Autumn } from 'autumn-js';

const app = express();
app.use(express.json());

// Initialize Autumn SDK
const autumn = new Autumn({
  secretKey: process.env.AUTUMN_SECRET_KEY,
});

// Error handling middleware
const asyncHandler = (fn) => (req, res, next) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

// POST /workspaces - Create a workspace entity in Autumn
app.post('/workspaces', asyncHandler(async (req, res) => {
  const { customerId, workspaceId, name, featureId } = req.body;

  // Validate required fields
  if (!customerId) {
    return res.status(400).json({ error: 'customerId is required' });
  }
  if (!workspaceId) {
    return res.status(400).json({ error: 'workspaceId is required' });
  }
  if (!name) {
    return res.status(400).json({ error: 'name is required' });
  }
  if (!featureId) {
    return res.status(400).json({ error: 'featureId is required' });
  }

  // Create the workspace entity
  const response = await autumn.entities.create({
    customerId,
    entityId: workspaceId,
    name,
    featureId,
  });

  res.status(201).json({
    workspaceId: response.entityId,
    customerId: response.customerId,
    name: response.name,
    featureId: response.featureId,
    createdAt: response.createdAt,
    balances: response.flags || {},
  });
}));

// POST /workspaces/:workspaceId/use-credits - Check and consume workspace credits
app.post('/workspaces/:workspaceId/use-credits', asyncHandler(async (req, res) => {
  const { workspaceId } = req.params;
  const { customerId, featureId, amount = 1 } = req.body;

  // Validate required fields
  if (!customerId) {
    return res.status(400).json({ error: 'customerId is required' });
  }
  if (!featureId) {
    return res.status(400).json({ error: 'featureId is required' });
  }
  if (amount <= 0) {
    return res.status(400).json({ error: 'amount must be greater than 0' });
  }

